// Import the actual Counterstake ABI from the build artifacts
// This is the same ABI used by the working script

// For now, we'll copy the essential parts of the ABI that we need
// In a production environment, you might want to dynamically import this

export const COUNTERSTAKE_ABI = [
  // Essential view functions for claim detection
  "function last_claim_num() view returns (uint64)",
  "function getClaim(uint256 claim_num) view returns (tuple(uint256 amount, address payable recipient_address, uint32 txts, uint32 ts, address payable claimant_address, uint32 expiry_ts, uint16 period_number, uint8 current_outcome, bool is_large, bool withdrawn, bool finished, string sender_address, string data, uint256 yes_stake, uint256 no_stake))",
  "function getClaim(string memory claim_id) view returns (tuple(uint256 amount, address payable recipient_address, uint32 txts, uint32 ts, address payable claimant_address, uint32 expiry_ts, uint16 period_number, uint8 current_outcome, bool is_large, bool withdrawn, bool finished, string sender_address, string data, uint256 yes_stake, uint256 no_stake))",
  "function getOngoingClaimNums() view returns (uint64[] memory)",
  "function stakes(uint256, uint8, address) view returns (uint256)",
  "function settings() view returns (address tokenAddress, uint16 ratio100, uint16 counterstake_coef100, uint32 min_tx_age, uint256 min_stake, uint256 large_threshold)",
  "function getRequiredStake(uint256 amount) view returns (uint256)",
  "function getChallengingPeriod(uint16 period_number, bool bLarge) view returns (uint256)",

  // Events
  "event NewClaim(uint256 indexed claim_num, address author_address, string sender_address, address recipient_address, string txid, uint32 txts, uint256 amount, int256 reward, uint256 stake, string data, uint32 expiry_ts)",
  "event NewChallenge(uint256 indexed claim_num, address author_address, uint256 stake, uint8 outcome, uint8 current_outcome, uint256 yes_stake, uint256 no_stake, uint32 expiry_ts, uint256 challenging_target)",
  "event FinishedClaim(uint256 indexed claim_num, uint8 outcome)",

  // State changing functions (for completeness)
  "function claim(string memory txid, uint32 txts, uint256 amount, int256 reward, uint256 stake, string memory sender_address, address payable recipient_address, string memory data) payable",
  "function challenge(uint256 claim_num, uint8 stake_on, uint256 stake) payable",
  "function challenge(string memory claim_id, uint8 stake_on, uint256 stake) payable",
  "function withdraw(uint256 claim_num) external",
  "function withdraw(string memory claim_id) external",
  "function withdraw(uint256 claim_num, address payable to_address) external",
  "function withdraw(string memory claim_id, address payable to_address) external",
];

// Export the same ABI for both export and import contracts since they both use Counterstake
export const EXPORT_ABI = COUNTERSTAKE_ABI;
export const IMPORT_WRAPPER_ABI = COUNTERSTAKE_ABI;
export const IMPORT_ABI = COUNTERSTAKE_ABI;
